BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "DIVIDEND" (
	"ID"	INTEGER,
	"PORTFOLIO_ID"	INTEGER,
	"TICKER"	TEXT,
	"AMOUNT"	REAL,
	"FX"	REAL,
	"DATE"	INTEGER,
	PRIMARY KEY("ID" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "SECURITY_VALUES" (
	"TICKER"	TEXT,
	"DATE"	TEXT,
	"OPEN"	REAL,
	"LOW"	REAL,
	"HIGH"	REAL,
	"CLOSE"	REAL,
	PRIMARY KEY("TICKER","DATE")
);
CREATE TABLE IF NOT EXISTS "FX" (
	"CURRENCY_CD"	TEXT,
	"DATE"	TEXT,
	"VALUE"	NUMERIC
);
CREATE TABLE IF NOT EXISTS "SECURITY" (
	"TICKER"	TEXT,
	"SECTOR"	TEXT,
	"COUNTRY"	TEXT,
	"FX"	INTEGER,
	"MARKET"	TEXT,
	"SRC"	TEXT,
	PRIMARY KEY("TICKER")
);
CREATE TABLE IF NOT EXISTS "FX_CD" (
	"FX"	TEXT,
	"CURRENCY_CD"	TEXT
);
CREATE TABLE IF NOT EXISTS "TRANSACTION" (
	"ID"	INTEGER,
	"TICKER"	TEXT,
	"AMOUNT"	REAL,
	"PRICE"	REAL,
	"FEE"	REAL,
	"FX"	REAL,
	"DATE"	TEXT,
	"KIND"	TEXT NOT NULL,
	PRIMARY KEY("ID" AUTOINCREMENT)
);
COMMIT;
